import React, { useState } from 'react';
import CameraList from './CameraList';
import CameraForm from './CameraForm';
import './CameraManagement.css';

function CameraManagement() {
  const [activeTab, setActiveTab] = useState('cameras');
  const [selectedCamera, setSelectedCamera] = useState(null);
  const [cameras, setCameras] = useState([]);
  const [showZoneDesigner, setShowZoneDesigner] = useState(false);
  const [showConfig, setShowConfig] = useState(false); // State để hiển thị config

  const tabs = [
    { id: 'cameras', label: '📷 Cameras', icon: '📹' },
  ];

  // Hàm xử lý khi thêm camera thành công
  const handleAddCamera = (newCamera) => {
    setCameras([...cameras, newCamera]);
    setShowZoneDesigner(false);
    // Hiển thị config của camera vừa thêm
    setSelectedCamera(newCamera);
    setShowConfig(true);

    // Log ra console để kiểm tra
    console.log('Camera added:', newCamera);
    console.log('Config:', newCamera.config);
  };

  return (
    <div className="camera-management">
      {/* Sidebar */}
      <div className="sidebar">
        <div className="logo">
          <h2>Camera Admin</h2>
          <span className="version">v2.0</span>
        </div>

        <nav className="nav-menu">
          {tabs.map(tab => (
            <button
              key={tab.id}
              className={`nav-item ${activeTab === tab.id ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <span className="nav-icon">{tab.icon}</span>
              <span className="nav-label">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="server-status">
            <span className="status-dot"></span>
            <span>Server: Online</span>
          </div>
          <div className="camera-stats">
            <small>Total: {cameras.length} cameras</small>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="main-content">
        {/* Header */}
        <div className="content-header">
          <h1>Camera Management</h1>
          <div className="header-actions">
            <button 
              className="btn-primary"
              onClick={() => setShowZoneDesigner(true)}
            >
              + New Camera
            </button>
          </div>
        </div>

        {/* Content Area */}
        <div className="content-area">
          {activeTab === 'cameras' && (
            <div className="cameras-view">
              {cameras.length > 0 ? (
                <>
                  <CameraList 
                    cameras={cameras}
                    setCameras={setCameras}
                    onSelectCamera={(cam) => {
                      setSelectedCamera(cam);
                      setShowConfig(true);
                    }}
                  />

                  {/* Hiển thị config của camera được chọn */}
                  {showConfig && selectedCamera && (
                    <div className="config-panel">
                      <div className="config-header">
                        <h3>Camera Configuration</h3>
                        <button 
                          className="btn-close"
                          onClick={() => setShowConfig(false)}
                        >
                          ×
                        </button>
                      </div>

                      <div className="config-content">
                        <div className="config-section">
                          <h4>Camera Info</h4>
                          <div className="info-row">
                            <span className="label">URL:</span>
                            <span className="value">{selectedCamera.cam_info?.url}</span>
                          </div>
                          <div className="info-row">
                            <span className="label">Camera ID:</span>
                            <span className="value">{selectedCamera.cam_info?.cam_id}</span>
                          </div>
                        </div>

                        <div className="config-section">
                          <h4>Zone Configuration</h4>
                          {selectedCamera.config?.zone && selectedCamera.config.zone.length > 0 ? (
                            <div className="zone-list">
                              {selectedCamera.config.zone.map((zone, index) => (
                                <div key={zone.ID || index} className="zone-item">
                                  <h5>Zone {index + 1}</h5>
                                  <div className="info-row">
                                    <span className="label">ID:</span>
                                    <span className="value">{zone.ID}</span>
                                  </div>
                                  <div className="info-row">
                                    <span className="label">Type:</span>
                                    <span className="value">
                                      {zone.type === 1 ? 'UNKNOWN_PERSON' : 
                                       zone.type === 2 ? 'NO_UNIFORM' : 
                                       zone.type === 3 ? 'ENTRY' : zone.type}
                                    </span>
                                  </div>
                                  {zone.axis && zone.axis.length > 0 && (
                                    <div className="info-row">
                                      <span className="label">Axis:</span>
                                      <span className="value">[{zone.axis.join(', ')}]</span>
                                    </div>
                                  )}
                                  {zone.coord && zone.coord.length > 0 && (
                                    <div className="info-row">
                                      <span className="label">Coord:</span>
                                      <span className="value">[{zone.coord.join(', ')}]</span>
                                    </div>
                                  )}
                                </div>
                              ))}
                            </div>
                          ) : (
                            <p className="no-data">No zones configured</p>
                          )}
                        </div>

                        <div className="config-section">
                          <h4>REID Settings</h4>
                          <div className="info-row">
                            <span className="label">FAISS Switch:</span>
                            <span className="value">{selectedCamera.config?.reid?.faiss_switch || 0.6}</span>
                          </div>
                          <div className="info-row">
                            <span className="label">FAISS Staff DB:</span>
                            <span className="value">{selectedCamera.config?.reid?.faiss_staff_db || 0.8}</span>
                          </div>
                        </div>

                        {/* JSON Preview */}
                        <div className="config-section">
                          <h4>Full JSON Output</h4>
                          <pre className="json-output">
                            {JSON.stringify({
                              list_camera: [{
                                cam_info: selectedCamera.cam_info,
                                config: selectedCamera.config
                              }]
                            }, null, 2)}
                          </pre>
                          <button 
                            className="btn-copy"
                            onClick={() => {
                              navigator.clipboard.writeText(JSON.stringify({
                                list_camera: [{
                                  cam_info: selectedCamera.cam_info,
                                  config: selectedCamera.config
                                }]
                              }, null, 2));
                              alert('Copied to clipboard!');
                            }}
                          >
                            📋 Copy JSON
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </>
              ) : (
                <div className="empty-state">
                  <p>Chưa có camera nào. Click "New Camera" để thêm mới.</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Quick Action Modal */}
      {showZoneDesigner && (
        <div className="modal-overlay">
          <div className="modal-content">
            <CameraForm 
              onSubmit={handleAddCamera}
              onClose={() => setShowZoneDesigner(false)}
            />
          </div>
        </div>
      )}

      <style jsx>{`
        .config-panel {
          margin-top: 30px;
          background: white;
          border-radius: 8px;
          box-shadow: 0 2px 8px rgba(0,0,0,0.1);
          overflow: hidden;
        }

        .config-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          padding: 15px 20px;
          background: #f8f9fa;
          border-bottom: 1px solid #dee2e6;
        }

        .config-header h3 {
          margin: 0;
          color: #2c3e50;
        }

        .btn-close {
          background: none;
          border: none;
          font-size: 24px;
          cursor: pointer;
          color: #6c757d;
        }

        .btn-close:hover {
          color: #343a40;
        }

        .config-content {
          padding: 20px;
        }

        .config-section {
          margin-bottom: 25px;
          padding-bottom: 20px;
          border-bottom: 1px solid #e9ecef;
        }

        .config-section:last-child {
          border-bottom: none;
          margin-bottom: 0;
          padding-bottom: 0;
        }

        .config-section h4 {
          margin: 0 0 15px 0;
          color: #495057;
          font-size: 16px;
        }

        .info-row {
          display: flex;
          margin-bottom: 10px;
          font-size: 14px;
        }

        .label {
          width: 120px;
          color: #6c757d;
          font-weight: 500;
        }

        .value {
          flex: 1;
          color: #212529;
          word-break: break-all;
        }

        .zone-list {
          display: grid;
          gap: 15px;
        }

        .zone-item {
          padding: 15px;
          background: #f8f9fa;
          border-radius: 6px;
          border-left: 3px solid #007bff;
        }

        .zone-item h5 {
          margin: 0 0 10px 0;
          color: #007bff;
        }

        .no-data {
          color: #6c757d;
          font-style: italic;
          margin: 0;
        }

        .json-output {
          background: #1e1e1e;
          color: #d4d4d4;
          padding: 15px;
          border-radius: 4px;
          font-size: 12px;
          font-family: 'Monaco', monospace;
          overflow-x: auto;
          max-height: 300px;
          margin: 15px 0;
        }

        .btn-copy {
          width: 100%;
          padding: 10px;
          background: #007bff;
          color: white;
          border: none;
          border-radius: 4px;
          cursor: pointer;
          font-size: 14px;
        }

        .btn-copy:hover {
          background: #0056b3;
        }

        .empty-state {
          text-align: center;
          padding: 60px;
          color: #6c757d;
          background: white;
          border-radius: 8px;
        }

        .modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0,0,0,0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 1000;
        }

        .modal-content {
          background: white;
          border-radius: 8px;
          padding: 20px;
          max-width: 500px;
          width: 90%;
          max-height: 90vh;
          overflow-y: auto;
        }
      `}</style>
    </div>
  );
}

export default CameraManagement;
